    const buildCron = (): string => {
        if (apFreqMode === "interval") return `${apMinute} */${apIntervalHours} * * *`;
        const days = [...apDays].sort().map(d => d === 0 ? 7 : d).join(",");
        return `${apMinute} ${apHour} * * ${days || "*"}`;
    };

