    // Shared phase computation — used by Pipeline, Kanban, and Insights views
    const NICHE_PHASE_ORDER: Record<string, number> = { niche: 0, catalog: 1, libro: 2, seo: 3, cover: 4, published: 5 };
    const nicheComputedPhases = useMemo(() => {
        const map = new Map<string, string>();
        for (const n of niches) {
            const storedPhase = (n.phase === "pdf" ? "seo" : n.phase) ?? "niche";
            const hasCatalogs = iaCatalogs.some(c => (c.nicheIds ?? []).includes(n._id));
            // bookPdfUrl on the niche is authoritative proof of a PDF even if no BookDraft record exists
            const hasDraft = bookDrafts.some(d => d.nicheId === n._id) || !!(n.bookPdfUrl);
            const hasListing = (n.listings?.length ?? 0) > 0;
            const hasCover = !!(n.coverUrl || (n.coverCandidates?.length ?? 0) > 0);
            const derivedPhase = (() => {
                if (storedPhase === "published") return "published";
                if (!hasCatalogs) return "niche";
                // Work backwards: each artifact implies all previous pipeline steps were done
                if (hasCover) return "cover";
                if (hasListing) return "seo";   // listing implies libro was completed
                if (hasDraft) return "libro";
                return "catalog";
            })();
            map.set(n._id, (NICHE_PHASE_ORDER[derivedPhase] ?? 0) >= (NICHE_PHASE_ORDER[storedPhase] ?? 0) ? derivedPhase : storedPhase);
        }
        return map;
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [niches, bookDrafts, iaCatalogs]);

    const [activeDraftId, setActiveDraftId] = useState<string | null>(null);
    const [confirmDeleteDraftId, setConfirmDeleteDraftId] = useState<string | null>(null);
    const [showAdvancedOptions, setShowAdvancedOptions] = useState(false);
    const [showCatalogAccordion, setShowCatalogAccordion] = useState(false);
    const [negativePrompt, setNegativePrompt] = useState("");
    const [inferenceSteps, setInferenceSteps] = useState(28);
    const [guidanceScale, setGuidanceScale] = useState(7.5);
    const [fixedSeed, setFixedSeed] = useState("");
    const [ideogramStyle, setIdeogramStyle] = useState("AUTO");
    const [initImageDataUrl, setInitImageDataUrl] = useState<string | null>(null);
    const [initImageStrength, setInitImageStrength] = useState(0.6);
    const [radarStorageKey, setRadarStorageKey] = useState("RADAR_ETSY_RESULT");

    const downloadFile = async (url: string, filename: string) => {
        try {
            if (url.startsWith("blob:") || url.startsWith("data:")) {
                const a = document.createElement("a");
                a.href = url;
                a.download = filename;
                document.body.appendChild(a);
                a.click();
                a.remove();
            } else {
                const res = await fetch(url);
                const blob = await res.blob();
                const blobUrl = URL.createObjectURL(blob);
                const a = document.createElement("a");
                a.href = blobUrl;
                a.download = filename;
                document.body.appendChild(a);
                a.click();
                a.remove();
                setTimeout(() => URL.revokeObjectURL(blobUrl), 5000);
            }
        } catch {
            toast.error("Error al descargar la imagen");
        }
    };

    const downloadPng = (url: string, filenameBase: string) => {
        void downloadFile(url, `${filenameBase}.png`);
    };

    const setGeneratedImageFromFile = (file: File) => {
        if (!file.type.startsWith("image/")) {
            toast.error("Solo se aceptan imágenes");
            return;
        }
        if (generatedImageObjectUrlRef.current) {
            URL.revokeObjectURL(generatedImageObjectUrlRef.current);
            generatedImageObjectUrlRef.current = null;
        }
        const url = URL.createObjectURL(file);
        generatedImageObjectUrlRef.current = url;
        setIsGenerating(false);
        setIsImageLoading(true);
        setGeneratedImage(url);
        toast.success("Imagen cargada");
    };

    const setInitImageFromFile = async (file: File) => {
        if (!file.type.startsWith("image/")) {
            toast.error("Solo se aceptan imágenes");
            return;
        }
        const reader = new FileReader();
        const dataUrl = await new Promise<string>((resolve, reject) => {
            reader.onerror = () => reject(new Error("read failed"));
            reader.onload = () => resolve(String(reader.result));
            reader.readAsDataURL(file);
        });
        setInitImageDataUrl(dataUrl);
        toast.success("Imagen de referencia añadida");
    };


    const ensureObjectUrl = async (url: string) => {
        if (url.startsWith("blob:")) return url;
        const res = await fetch(url);
        const blob = await res.blob();
        const objectUrl = URL.createObjectURL(blob);
        return objectUrl;
    };

    const saveBookDraft = async () => {
        setIsSavingDraft(true);
        try {
            const serializablePages = bookPages.map(p => ({
                ...p,
                image: p.image?.url.startsWith("blob:") ? undefined : p.image,
            }));
            const draftId = activeDraftId;
            // Carry existing nicheId if set, or detect from pipeline- prefix
            const existingNicheId = bookDrafts.find(d => d.id === draftId)?.nicheId;
            const prefixMatch = draftId?.match(/^pipeline-([a-f0-9]{24})/);
            const linkedNicheId = existingNicheId ?? prefixMatch?.[1];

            const isMongoId = /^[a-f0-9]{24}$/.test(draftId ?? "");
            let savedId: string;

            if (draftId && isMongoId) {
                // Existing MongoDB draft → PATCH
                const res = await fetch(`${API_BASE_URL}/book-drafts/${draftId}`, {
                    method: "PATCH",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ fileName: bookFileName, pages: serializablePages, ...(linkedNicheId ? { nicheId: linkedNicheId } : {}) }),
                });
                if (!res.ok) throw new Error("Error guardando borrador");
                savedId = draftId;
            } else {
                // New draft → POST
                const res = await fetch(`${API_BASE_URL}/book-drafts`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ fileName: bookFileName, pages: serializablePages, ...(linkedNicheId ? { nicheId: linkedNicheId } : {}) }),
                });
                if (!res.ok) throw new Error("Error guardando borrador");
                const resData = await res.json();
                savedId = String(resData.draft._id);
            }

            const savedDraft = { id: savedId, fileName: bookFileName, pages: serializablePages, savedAt: new Date().toISOString(), ...(linkedNicheId ? { nicheId: linkedNicheId } : {}) };
            setActiveDraftId(savedId);
            setBookDrafts(prev => {
                const exists = draftId && prev.some(d => d.id === draftId);
                return exists ? prev.map(d => d.id === draftId ? savedDraft : d) : [...prev, savedDraft];
            });

            // If this draft is linked to a niche, advance to "libro" phase
            if (linkedNicheId) {
                const niche = niches.find(n => n._id === linkedNicheId);
                if (niche && (niche.phase === "catalog" || niche.phase === "niche")) {
                    await fetch(`${API_BASE_URL}/niches/${linkedNicheId}`, {
                        method: "PATCH",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({ phase: "libro" }),
                    }).catch(() => {});
                    setNiches(prev => prev.map(n => n._id === linkedNicheId ? { ...n, phase: "libro" } : n));
                }
            }

            toast.success("Borrador guardado");
        } catch {
            toast.error("Error al guardar el borrador");
        } finally {
            setIsSavingDraft(false);
        }
    };

    const deleteBookDraft = async (draftId: string) => {
        setBookDrafts(prev => prev.filter(d => d.id !== draftId));
        if (activeDraftId === draftId) {
            setBookPages([]);
            setSelectedPageId(null);
            setBookFileName("libro-kdp");
            setActiveDraftId(null);
            setBookEditorOpen(false);
        }
        // Delete from MongoDB if it's a MongoDB ID
        if (/^[a-f0-9]{24}$/.test(draftId)) {
            await fetch(`${API_BASE_URL}/book-drafts/${draftId}`, { method: "DELETE" }).catch(() => {});
        }
    };

    // Auto-saves current pages before switching to another draft
    const guardedLoadBookDraft = async (draft: { id: string; fileName: string; pages: BookPage[]; savedAt: string; nicheId?: string }) => {
        if (bookPages.length > 0 && activeDraftId !== draft.id) {
            // Persist current state silently before switching
            const serializablePages = bookPages.map(p => ({
                ...p,
                image: p.image?.url.startsWith("blob:") ? undefined : p.image,
            }));
            const draftId = activeDraftId;
            const isMongoId = /^[a-f0-9]{24}$/.test(draftId ?? "");
            if (draftId && isMongoId) {
                fetch(`${API_BASE_URL}/book-drafts/${draftId}`, {
                    method: "PATCH",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ fileName: bookFileName, pages: serializablePages }),
                }).catch(() => {});
            } else {
                // New unsaved draft — save to API
                fetch(`${API_BASE_URL}/book-drafts`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ fileName: bookFileName, pages: serializablePages }),
                }).then(r => r.ok ? r.json() : null).then(data => {
                    if (data?.draft?._id) {
                        const newId = String(data.draft._id);
                        setBookDrafts(prev => {
                            const snap = { id: newId, fileName: bookFileName, pages: serializablePages, savedAt: new Date().toISOString() };
                            return draftId ? prev.map(d => d.id === draftId ? snap : d) : [...prev, snap];
                        });
                    }
                }).catch(() => {});
            }
        }
        setBookPages(draft.pages);
        setSelectedPageId(draft.pages[0]?.id ?? null);
        setBookFileName(draft.fileName);
        setActiveDraftId(draft.id);
        setBookEditorOpen(true);
    };

    const newBookDraft = () => {
        setBookPages([]);
        setSelectedPageId(null);
        setBookFileName("libro-kdp");
        setActiveDraftId(null);
        setBookEditorOpen(true);
    };

    const downloadCatalogPdfDirect = async (catalog: { _id: string; name: string; images: { url: string }[] }) => {
        if (!catalog.images.length) return;
        setDirectPdfCatalogId(catalog._id);
        try {
            const pages: BookPage[] = catalog.images.map((img, i) => ({
                id: `dp-${i}-${Date.now()}`,
                type: "image" as const,
                image: { url: img.url, scale: 1, label: `${catalog.name} #${i + 1}` },
                text: defaultTextStyle(),
            }));
            const bytes = await buildBookPdf(undefined, false, pages, true);
            if (!bytes) throw new Error("No se pudo generar el PDF");
            const blob = new Blob([bytes as BlobPart], { type: "application/pdf" });
            const blobUrl = URL.createObjectURL(blob);
            const a = document.createElement("a");
            a.href = blobUrl;
            a.download = `${catalog.name || "libro-kdp"}.pdf`;
            a.click();
            toast.success(`PDF generado · ${catalog.images.length} páginas`);
        } catch (e: any) {
            toast.error(e.message ?? "Error generando PDF");
        } finally {
            setDirectPdfCatalogId(null);
        }
    };

    const downloadNichePdfDirect = async (niche: NicheFE, linkedCats: typeof iaCatalogs) => {
        const catImages = linkedCats.flatMap(c => c.images);
        const persistentCloudImgs = cloudinaryImages.filter(img => img.nicheId === niche._id);
        const allImages = [
            ...catImages,
            ...persistentCloudImgs.map(img => ({ url: img.url, publicId: img.publicId, width: img.width, height: img.height, bytes: img.bytes, createdAt: img.createdAt ?? "" })),
        ];
        if (!allImages.length) { toast.error("Este nicho no tiene imágenes aún"); return; }
        setDirectNichePdfId(niche._id);
        try {
            const pages: BookPage[] = allImages.map((img, i) => ({
                id: `np-${i}-${Date.now()}`,
                type: "image" as const,
                image: { url: img.url, scale: 1, label: `${niche.name} #${i + 1}` },
                text: defaultTextStyle(),
            }));
            const bytes = await buildBookPdf(undefined, false, pages, true);
            if (!bytes) throw new Error("No se pudo generar el PDF");
            const blob = new Blob([bytes as BlobPart], { type: "application/pdf" });
            const blobUrl = URL.createObjectURL(blob);
            const a = document.createElement("a");
            a.href = blobUrl;
            a.download = `${niche.name || "nicho-kdp"}.pdf`;
            a.click();
            toast.success(`PDF generado · ${allImages.length} imágenes`);
        } catch (e: any) {
            toast.error(e.message ?? "Error generando PDF");
        } finally {
            setDirectNichePdfId(null);
        }
    };

    const buildBookPdf = async (onBytes?: (bytes: Uint8Array) => void, compressImages = false, pagesToUse?: BookPage[], forceNoOwnerPage = false) => {
        const pages = pagesToUse ?? bookPages;
        if (pages.length === 0) return null;
        setIsBuildingPdf(true);
        try {
            const pdf = await PDFDocument.create();
            const fontkitMod = await import("@pdf-lib/fontkit");
            pdf.registerFontkit(fontkitMod.default ?? fontkitMod);
            const sizeConfig = KDP_BOOK_SIZES.find(s => s.id === bookPdfSize) ?? KDP_BOOK_SIZES[0];
            const pageWidth = sizeConfig.w;
            const pageHeight = sizeConfig.h;
            const margin = sizeConfig.margin;

            // Compress an image via Canvas → JPEG. Fetches bytes first to avoid CORS issues.
            const compressToJpeg = async (url: string, quality = 0.68): Promise<Uint8Array> => {
                // Fetch bytes directly (works for any origin via fetch)
                let rawBytes: Uint8Array;
                try {
                    const res = await fetch(url);
                    rawBytes = new Uint8Array(await res.arrayBuffer());
                } catch {
                    const objectUrl = await ensureObjectUrl(url);
                    const res = await fetch(objectUrl);
                    rawBytes = new Uint8Array(await res.arrayBuffer());
                }
                // Create a local blob URL — canvas loads this without CORS restrictions
                const blobUrl = URL.createObjectURL(new Blob([rawBytes as BlobPart]));
                return new Promise((resolve, reject) => {
                    const img = new Image();
                    img.onload = () => {
                        URL.revokeObjectURL(blobUrl);
                        const MAX = 1400;
                        let { naturalWidth: w, naturalHeight: h } = img;
                        if (w > MAX || h > MAX) {
                            const r = Math.min(MAX / w, MAX / h);
                            w = Math.round(w * r); h = Math.round(h * r);
                        }
                        const canvas = document.createElement("canvas");
                        canvas.width = w; canvas.height = h;
                        const ctx = canvas.getContext("2d")!;
                        ctx.fillStyle = "#fff";
                        ctx.fillRect(0, 0, w, h);
                        ctx.drawImage(img, 0, 0, w, h);
                        canvas.toBlob(blob => {
                            if (!blob) { reject(new Error("Canvas blob failed")); return; }
                            blob.arrayBuffer().then(buf => resolve(new Uint8Array(buf)));
                        }, "image/jpeg", quality);
                    };
                    img.onerror = () => { URL.revokeObjectURL(blobUrl); reject(new Error("img load failed")); };
                    img.src = blobUrl;
                });
            };

            const embedImage = async (url: string) => {
                if (compressImages) {
                    try {
                        const jpegBytes = await compressToJpeg(url);
                        return await pdf.embedJpg(jpegBytes);
                    } catch { /* fall through to original method */ }
                }
                let bytes: Uint8Array;
                try {
                    const res = await fetch(url);
                    bytes = new Uint8Array(await res.arrayBuffer());
                } catch {
                    const objectUrl = await ensureObjectUrl(url);
                    const res = await fetch(objectUrl);
                    bytes = new Uint8Array(await res.arrayBuffer());
                }
                try { return await pdf.embedPng(bytes); } catch { return await pdf.embedJpg(bytes); }
            };

            const drawImageCentered = (page: any, embedded: any, zoom: number = 1) => {
                const effectiveMargin = margin / Math.max(zoom, 0.1);
                const maxW = pageWidth - effectiveMargin * 2;
                const maxH = pageHeight - effectiveMargin * 2;
                const imgScale = Math.min(maxW / embedded.width, maxH / embedded.height);
                const drawW = embedded.width * imgScale;
                const drawH = embedded.height * imgScale;
                const imgX = (pageWidth - drawW) / 2;
                const imgY = (pageHeight - drawH) / 2;
                page.drawImage(embedded, { x: imgX, y: imgY, width: drawW, height: drawH });
                return { x: imgX, y: imgY, w: drawW, h: drawH };
            };

            // Fetch and embed Roboto TTF so all fonts are fully embedded (KDP requirement)
            const fontRes = await fetch("/fonts/Geist-Regular.ttf");
            const embeddedFont = await pdf.embedFont(new Uint8Array(await fontRes.arrayBuffer()));

            const drawTextOnPage = async (pdfPage: any, style: PageTextStyle) => {
                const text = style.content.trim();
                if (!text) return;
                const font = embeddedFont;
                const fontSize = style.fontSize;
                const hex = style.color.replace("#", "");
                const textColor = rgb(parseInt(hex.slice(0, 2), 16) / 255, parseInt(hex.slice(2, 4), 16) / 255, parseInt(hex.slice(4, 6), 16) / 255);
                // Handle multi-line: split by newline and render each line
                const lines = text.split("\n");
                const lineH = fontSize * 1.3;
                const blockH = lines.length * lineH;
                let yStart: number;
                if (style.verticalAlign === "top") yStart = pageHeight - margin - fontSize;
                else if (style.verticalAlign === "middle") yStart = (pageHeight + blockH) / 2 - fontSize;
                else yStart = margin + blockH - fontSize; // bottom
                lines.forEach((line, i) => {
                    const w = font.widthOfTextAtSize(line || " ", fontSize);
                    let x = margin;
                    if (style.align === "center") x = Math.max(margin, (pageWidth - w) / 2);
                    else if (style.align === "right") x = Math.max(margin, pageWidth - margin - w);
                    pdfPage.drawText(line || " ", { x, y: yStart - i * lineH, size: fontSize, font, color: textColor });
                });
            };

            // ── Helper: draws the owner/copyright page content scaled to any page size ──
            const drawOwnerPageContent = (pg: any, font: any) => {
                const cx = pageWidth / 2;
                const grayMid = rgb(0.5, 0.5, 0.5);
                const grayLight = rgb(0.78, 0.78, 0.78);
                const grayVeryLight = rgb(0.88, 0.88, 0.88);

                // "pertenece a" section — positioned at ~66.5% and ~63.7% from bottom
                const belongsY  = pageHeight * 0.665;
                const belongsEnY = pageHeight * 0.637;
                const labelSize = Math.round(15 * (pageHeight / 841.89));
                const spanishText = "Este libro pertenece a:";
                const englishText = "This book belongs to:";
                pg.drawText(spanishText, { x: cx - font.widthOfTextAtSize(spanishText, labelSize) / 2, y: belongsY, size: labelSize, font, color: grayMid });
                pg.drawText(englishText, { x: cx - font.widthOfTextAtSize(englishText, labelSize - 1) / 2, y: belongsEnY, size: labelSize - 1, font, color: grayLight });

                // Dotted line at ~60.3% from bottom
                const lineY = pageHeight * 0.603;
                const lineX1 = margin + 50 * (pageWidth / 612);
                const lineX2 = pageWidth - margin - 50 * (pageWidth / 612);
                for (let x = lineX1; x < lineX2; x += 8) {
                    pg.drawLine({ start: { x, y: lineY }, end: { x: Math.min(x + 4, lineX2), y: lineY }, thickness: 0.8, color: grayLight });
                }

                // Color test squares at ~12.8% from bottom
                const squareSize = Math.round(30 * (pageWidth / 612));
                const squareCount = 6;
                const squareGap = Math.round(9 * (pageWidth / 612));
                const totalW = squareCount * squareSize + (squareCount - 1) * squareGap;
                const squareStartX = cx - totalW / 2;
                const squareY = pageHeight * 0.128;
                const colorTestLabel = "Prueba tus colores aquí  ·  Test your colors here";
                const colorLabelSize = Math.max(5, 7.5 * (pageHeight / 841.89));
                pg.drawText(colorTestLabel, { x: cx - font.widthOfTextAtSize(colorTestLabel, colorLabelSize) / 2, y: squareY + squareSize + 10, size: colorLabelSize, font, color: grayMid });
                pg.drawRectangle({ x: squareStartX - 6, y: squareY - 6, width: totalW + 12, height: squareSize + 12, borderColor: grayVeryLight, borderWidth: 0.5, color: rgb(1, 1, 1) });
                for (let i = 0; i < squareCount; i++) {
                    pg.drawRectangle({ x: squareStartX + i * (squareSize + squareGap), y: squareY, width: squareSize, height: squareSize, borderColor: grayLight, borderWidth: 0.6, color: rgb(1, 1, 1) });
                }

                // Copyright line — just above the margin
                const copyrightText = `© ${new Date().getFullYear()} Emilio Jiménez. Todos los derechos reservados.`;
                const copyrightSize = Math.max(5, 7 * (pageHeight / 841.89));
                pg.drawText(copyrightText, { x: cx - font.widthOfTextAtSize(copyrightText, copyrightSize) / 2, y: margin + 8, size: copyrightSize, font, color: grayVeryLight });
            };

            // ── Página de propietario / copyright (primera página, si no viene en pages) ──
            if (includeOwnerPage && !forceNoOwnerPage && !pages.some(p => p.type === "owner")) {
                const ownerPage = pdf.addPage([pageWidth, pageHeight]);
                drawOwnerPageContent(ownerPage, embeddedFont);
            }

            for (const bookPage of pages) {
                // ── Owner page type: render same content as standalone owner page ──
                if (bookPage.type === "owner") {
                    const ownerPage = pdf.addPage([pageWidth, pageHeight]);
                    drawOwnerPageContent(ownerPage, embeddedFont);
                    continue;
                }

                const pdfPage = pdf.addPage([pageWidth, pageHeight]);
                if (bookPage.image) {
                    const embedded = await embedImage(bookPage.image.url);
                    drawImageCentered(pdfPage, embedded, bookPage.image.scale ?? 1);
                    if (bookPage.image.border) {
                        const hexToRgb = (hex: string) => {
                            const r = parseInt(hex.slice(1, 3), 16) / 255;
                            const g = parseInt(hex.slice(3, 5), 16) / 255;
                            const b = parseInt(hex.slice(5, 7), 16) / 255;
                            return rgb(r, g, b);
                        };
                        const bw = bookPage.image.border.width;
                        pdfPage.drawRectangle({
                            x: bw / 2,
                            y: bw / 2,
                            width: pageWidth - bw,
                            height: pageHeight - bw,
                            borderColor: hexToRgb(bookPage.image.border.color),
                            borderWidth: bw,
                        });
                    }
                }
                if ((bookPage.type === "text" || bookPage.type === "both") && bookPage.text.content.trim()) {
                    await drawTextOnPage(pdfPage, bookPage.text);
                }
            }

            const pdfBytes = await pdf.save();
            if (onBytes) {
                onBytes(pdfBytes as Uint8Array);
                return pdfBytes as Uint8Array;
            }
            const blob = new Blob([pdfBytes as Uint8Array<ArrayBuffer>], { type: "application/pdf" });
            const url = URL.createObjectURL(blob);
            downloadFile(url, `${(bookFileName.trim() || "libro-kdp")}_${bookPdfSize}.pdf`);
            setTimeout(() => URL.revokeObjectURL(url), 30_000);
            toast.success("PDF generado");
            return pdfBytes as Uint8Array;
        } catch (e) {
            console.error(e);
            toast.error("No se pudo generar el PDF");
            return null;
        } finally {
            setIsBuildingPdf(false);
        }
    };

    // Vault persistence: load non-blob images from localStorage on mount
    useEffect(() => {
        try {
            const saved = localStorage.getItem("kdp-vault-images");
            if (saved) {
                const parsed: { url: string; model: string; dim: string; seed?: number }[] = JSON.parse(saved);
                const valid = parsed.filter(img => !img.url.startsWith("blob:"));
                if (valid.length > 0) setVaultImages(valid);
            }
        } catch { /* ignore */ }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    useEffect(() => {
        try {
            const toSave = vaultImages.filter(img => !img.url.startsWith("blob:"));
            localStorage.setItem("kdp-vault-images", JSON.stringify(toSave));
        } catch { /* ignore */ }
    }, [vaultImages]);

    // Load favorites + book draft from MongoDB on mount
    useEffect(() => {
        const load = async () => {
            try {
                const res = await fetch(`${API_BASE_URL}/settings`);
                if (!res.ok) return;
                const data = await res.json();

                // Favorites
                const favFound = (data.settings ?? []).find((s: any) => s.key === "kdp-favorites");
                if (Array.isArray(favFound?.value) && favFound.value.length > 0) {
                    const map = new Map<string, FavoriteImage>();
                    for (const item of favFound.value) {
                        if (typeof item === "string") {
                            map.set(item, { url: item, label: "", source: "generated", savedAt: new Date().toISOString() });
                        } else if (item && typeof item.url === "string") {
                            map.set(item.url, item as FavoriteImage);
                        }
                    }
                    setFavorites(map);
                }

                // Autopilot rules + notification rules
                const apRulesFound = (data.settings ?? []).find((s: any) => s.key === "AUTOPILOT_RULES");
                if (apRulesFound?.value) { try { const r = JSON.parse(apRulesFound.value); if (Array.isArray(r)) setApRules(r); } catch { } }
                const notifFound = (data.settings ?? []).find((s: any) => s.key === "NOTIFICATION_RULES");

                // Autopilot numeric limits
                const settingsMap = new Map<string, string>((data.settings ?? []).map((s: any) => [s.key, s.value]));
                if (settingsMap.has("AUTOPILOT_CATALOGS_PER_NICHE")) setApCatalogsPer(settingsMap.get("AUTOPILOT_CATALOGS_PER_NICHE")!);
                if (settingsMap.has("AUTOPILOT_IMAGES_PER_CATALOG")) setApImagesPerCatalog(settingsMap.get("AUTOPILOT_IMAGES_PER_CATALOG")!);
                if (settingsMap.has("AUTOPILOT_MAX_NICHES")) setApMaxNiches(settingsMap.get("AUTOPILOT_MAX_NICHES")!);
                if (settingsMap.has("MAX_ACTIVE_CATALOGS")) setApMaxActiveCatalogs(settingsMap.get("MAX_ACTIVE_CATALOGS")!);
                if (settingsMap.has("QUALITY_CHECK_ENABLED")) setQualityCheckEnabled(settingsMap.get("QUALITY_CHECK_ENABLED") !== "0" && settingsMap.get("QUALITY_CHECK_ENABLED") !== "false");
                if (settingsMap.has("QUALITY_VAULT_TELEGRAM_NOTIFY")) setQualityVaultTelegramEnabled(settingsMap.get("QUALITY_VAULT_TELEGRAM_NOTIFY") === "1" || settingsMap.get("QUALITY_VAULT_TELEGRAM_NOTIFY") === "true");
                if (settingsMap.has("TELEGRAM_WEEKLY_DIGEST")) setWeeklyDigestEnabled(settingsMap.get("TELEGRAM_WEEKLY_DIGEST") !== "false");

                // Autopilot schedule — restore cron UI state
                const savedCron = settingsMap.get("AUTOPILOT_CRON") ?? "";
                if (savedCron.trim()) {
                    setApScheduled(true);
                    const parts = savedCron.trim().split(/\s+/);
                    if (parts.length >= 5) {
                        const [cronMin, cronHour, , , cronDays] = parts;
                        if (cronHour.startsWith("*/")) {
                            setApFreqMode("interval");
                            setApIntervalHours(cronHour.slice(2));
                            setApMinute(cronMin);
                        } else {
                            setApFreqMode("specific");
                            setApHour(parseInt(cronHour) || 9);
                            setApMinute(cronMin);
                            if (cronDays && cronDays !== "*") {
                                const days = cronDays.split(",").map(d => { const n = parseInt(d); return n === 7 ? 0 : n; }).filter(n => !isNaN(n));
                                setApDays(new Set(days));
                            }
                        }
                    }
                } else {
                    setApScheduled(false);
                }

                // Alert settings (hours only)
                const alertMap = new Map<string, string>((data.settings ?? []).map((s: any) => [s.key, String(s.value)]));
                const newAlerts: typeof alertSettings = { ...alertSettings };
                for (const k of Object.keys(alertSettings)) { if (alertMap.has(k)) (newAlerts as any)[k] = alertMap.get(k)!; }
                setAlertSettings(newAlerts);

                // Notification rules
                if (notifFound?.value) {
                    try {
                        const rules = JSON.parse(notifFound.value) as Array<{ id: string; enabled: boolean }>;
                        if (Array.isArray(rules)) {
                            const map: Record<string, boolean> = Object.fromEntries(NOTIFICATION_EVENTS.map(e => [e.id, true]));
                            for (const r of rules) map[r.id] = r.enabled;
                            setNotificationRules(map);
                        }
                    } catch { /* keep defaults */ }
                }

                // Book drafts — load from MongoDB API, migrate from Settings if empty
                try {
                    const draftsRes = await fetch(`${API_BASE_URL}/book-drafts`);
                    if (draftsRes.ok) {
                        const draftsData = await draftsRes.json();
                        if (draftsData.drafts && draftsData.drafts.length > 0) {
                            setBookDrafts(draftsData.drafts.map((d: any) => ({
                                id: String(d._id),
                                fileName: d.fileName,
                                pages: d.pages ?? [],
                                savedAt: typeof d.savedAt === "string" ? d.savedAt : new Date(d.savedAt).toISOString(),
                                nicheId: d.nicheId,
                            })));
                        } else {
                            // Migrate from Settings if no MongoDB drafts yet
                            const draftsFound = (data.settings ?? []).find((s: any) => s.key === "kdp-book-drafts");
                            const settingsDrafts: any[] = draftsFound?.value && Array.isArray(draftsFound.value) ? draftsFound.value
                                : (() => {
                                    const legacyDraft = (data.settings ?? []).find((s: any) => s.key === "kdp-book-draft");
                                    return legacyDraft?.value?.pages ? [{ id: "draft-legacy", fileName: legacyDraft.value.fileName ?? "libro-kdp", pages: legacyDraft.value.pages, savedAt: new Date().toISOString() }] : [];
                                })();
                            if (settingsDrafts.length > 0) {
                                setBookDrafts(settingsDrafts);
                                // Migrate to MongoDB in background
                                for (const d of settingsDrafts) {
                                    fetch(`${API_BASE_URL}/book-drafts`, {
                                        method: "POST",
                                        headers: { "Content-Type": "application/json" },
                                        body: JSON.stringify({ fileName: d.fileName, pages: d.pages ?? [], savedAt: d.savedAt, nicheId: d.nicheId }),
                                    }).then(r => r.ok ? r.json() : null).then(data => {
                                        if (data?.draft?._id) {
                                            setBookDrafts(prev => prev.map(existing => existing.id === d.id ? { ...existing, id: String(data.draft._id) } : existing));
                                        }
                                    }).catch(() => {});
                                }
                            }
                        }
                    }
                } catch { /* silent — drafts load is non-critical */ }
            } catch { }
        };
        void load();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    useEffect(() => {
        return () => {
            if (generatedImageObjectUrlRef.current) {
                URL.revokeObjectURL(generatedImageObjectUrlRef.current);
                generatedImageObjectUrlRef.current = null;
            }
            if (previewImageObjectUrlRef.current) {
                URL.revokeObjectURL(previewImageObjectUrlRef.current);
                previewImageObjectUrlRef.current = null;
            }
        };
    }, []);

    // Load all data on mount in parallel — no tab gating so every section is ready when first visited
    useEffect(() => {
        void fetchProducts();
        void fetchIntegrations();
        void fetchNiches();
        void fetchCloudinaryImages();
        void fetchSavedPrompts();
        setLoadingGelatoData(true);
        Promise.all([
            fetch(`${API_BASE_URL}/gelato/store/products?limit=50`).then(r => r.ok ? r.json() : { products: [] }).catch(() => ({ products: [] })),
            fetch(`${API_BASE_URL}/gelato/orders?limit=10`).then(r => r.ok ? r.json() : { orders: [] }).catch(() => ({ orders: [] })),
        ]).then(([prod, ord]) => {
            setGelatoStoreProducts(prod.products ?? []);
            setGelatoOrders(ord.orders ?? []);
        }).finally(() => setLoadingGelatoData(false));
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // Global paste listener: when in creation tab and no image is being shown/generated,
    // paste goes directly to the vault (no need to click the card first)
    const addImageFileToVaultRef = useRef(addImageFileToVault);
    useEffect(() => { addImageFileToVaultRef.current = addImageFileToVault; });
    useEffect(() => {
        if (activeTab !== "creation") return;
        const handleGlobalPaste = (e: ClipboardEvent) => {
            if (generatedImage || isGenerating) return;
            const target = e.target as HTMLElement;
            if (target.tagName === "INPUT" || target.tagName === "TEXTAREA" || target.isContentEditable) return;
            const items = Array.from(e.clipboardData?.items || []);
            const imageItem = items.find(it => it.kind === "file" && it.type.startsWith("image/"));
            const file = imageItem?.getAsFile();
            if (file) addImageFileToVaultRef.current(file);
        };
        document.addEventListener("paste", handleGlobalPaste);
        return () => document.removeEventListener("paste", handleGlobalPaste);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeTab, generatedImage, isGenerating]);

    const fetchTimeseries = async (days: 30 | 60 | 90 = 30) => {
        try {
            const res = await fetch(`${API_BASE_URL}/insights/timeseries?days=${days}`);
            if (res.ok) { const d = await res.json(); setTimeseries(d); }
        } catch { /* ignore */ }
    };

    // Fetch catalogs on mount (socket connects when entering creation tab)
    useEffect(() => { void fetchCatalogs(); void fetchApRuns(); void fetchPipelineData(); void fetchRejectedImages(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

    useEffect(() => { if (activeTab === "insights") void fetchTimeseries(timeseriesDays); }, [activeTab, timeseriesDays]); // eslint-disable-line react-hooks/exhaustive-deps

    // Always keep catalog socket connected so images appear in real-time on any tab
    useEffect(() => {
        const socket = createApiSocket(API_BASE_URL);
        catalogSocketRef.current = socket;

        // Sync halo on connect/reconnect — in case the socket missed an autopilot:done event
        const syncApRunning = () => {
            fetch(`${API_BASE_URL}/autopilot/status`)
                .then(r => r.json())
                .then((d: any) => { if (typeof d.running === "boolean") setApRunning(d.running); })
                .catch(() => {});
        };
        socket.on("connect", syncApRunning);
        syncApRunning(); // also run immediately on mount

        socket.on("catalog:progress", (data: { catalogId: string; status: string; current: number; total: number; image?: CatalogImageFE; lastError?: string; skipped?: number; promptSnippet?: string; imageStartedAt?: number }) => {
            setIaCatalogs((prev) =>
                prev.map((c) => {
                    if (c._id !== data.catalogId) return c;
                    const updated: IACatalogFE = {
                        ...c,
                        status: data.status as IACatalogFE["status"],
                        lastError: data.lastError !== undefined ? data.lastError : c.lastError,
                        skippedImages: data.skipped !== undefined ? data.skipped : c.skippedImages,
                        currentPrompt: data.promptSnippet !== undefined ? data.promptSnippet : c.currentPrompt,
                        // Track when the current image started (reset when a new slot begins, clear when image arrives)
                        imageStartedAt: data.imageStartedAt !== undefined ? data.imageStartedAt : (data.image ? undefined : c.imageStartedAt),
                    };
                    if (data.image) {
                        const alreadyExists = updated.images.some((img) => img.publicId === data.image!.publicId);
                        if (!alreadyExists) updated.images = [...updated.images, data.image];
                    }
                    return updated;
                })
            );
        });

        socket.on("catalog:completed", (data: { catalogId: string }) => {
            setIaCatalogs((prev) => {
                const updated: IACatalogFE[] = prev.map((c) => (c._id === data.catalogId ? { ...c, status: "completed" as const, lastError: "" } : c));
                const catalog = updated.find(c => c._id === data.catalogId);
                toast.success(`"${catalog?.name ?? "Catálogo"}" completado · ${catalog?.images?.length ?? 0} imágenes`);
                return updated;
            });
        });

        socket.on("catalog:queue-activated", (data: { catalogId: string; status: string; name: string }) => {
            setIaCatalogs((prev) =>
                prev.map((c) => (c._id === data.catalogId ? { ...c, status: "running" } : c))
            );
            toast.info(`Cola: iniciando "${data.name}" — primera imagen en 2 min`);
        });

        socket.on("catalog:error", (data: { catalogId: string; error: string }) => {
            setIaCatalogs((prev) =>
                prev.map((c) => (c._id === data.catalogId ? { ...c, status: "failed", lastError: data.error } : c))
            );
            toast.error(`Error en catálogo: ${data.error}`);
        });

        socket.on("autopilot:log", (data: { nicheId: string; message: string }) => {
            setApRunning(true);
            setApLogs(prev => [...prev.slice(-49), { nicheId: data.nicheId, message: data.message, ts: Date.now() }]);
        });

        socket.on("autopilot:stage", (data: { stage: "discovery" | "prompt" | "sample" | "catalog" | "libro" | "listing" | "cover"; nicheId: string; nicheName: string }) => {
            setApStage(data.stage);
            setApCurrentNicheName(data.nicheName);
            setApCurrentNicheId(data.nicheId);
        });

        socket.on("autopilot:done", (data: { processed: number; timestamp?: string }) => {
            setApRunning(false);
            setApCurrentNicheName(null);
            setApCurrentNicheId(null);
            setApStage(null);
            // Clear pipeline running state — server cycle is done
            pipelineRunningRef.current = null;
            setPipelineRunningId(null);
            setPipelineQueueIds([]);
            pipelineQueueRef.current = [];
            const msg = `✅ Completado · ${data.processed} nicho${data.processed !== 1 ? "s" : ""} procesado${data.processed !== 1 ? "s" : ""}`;
            setApLogs(prev => [...prev.slice(-49), { nicheId: "", message: msg, ts: Date.now() }]);
            toast.success(msg);
            void fetchNiches();
            void fetchApRuns();
        });

        socket.on("autopilot:error", (data: { message: string }) => {
            setApRunning(false);
            setApCurrentNicheName(null);
            setApCurrentNicheId(null);
            setApStage(null);
            const msg = `⛔ Detenido: ${data.message}`;
            setApLogs(prev => [...prev.slice(-49), { nicheId: "", message: msg, ts: Date.now() }]);
            toast.error(`Auto-Pilot detenido — ${data.message}`, { duration: 8000 });
            void fetchApRuns();
        });

        socket.on("niches:updated", () => {
            void fetchNiches();
            void fetchPipelineData();
        });

        socket.on("catalogs:updated", () => {
            void fetchCatalogs();
            void fetchPipelineData();
        });

        socket.on("autopilot:stage", () => {
            void fetchPipelineData();
        });

        socket.on("autopilot:done", () => {
            void fetchPipelineData();
        });

        socket.on("telegram:open-pdf", (data: { nicheId: string; nicheName: string; catalogIds: string[] }) => {
            setKdpTemplateCatalogSel(new Set(data.catalogIds));
            setKdpTemplateOpen(true);
            changeTab("creation");
            toast.success(`📄 PDF de "${data.nicheName}" — ${data.catalogIds.length} catálogo${data.catalogIds.length > 1 ? "s" : ""} pre-seleccionado${data.catalogIds.length > 1 ? "s" : ""}`, { duration: 6000 });
        });

        socket.on("telegram:notification", (data) => {
            const fn = data.type === "error" ? toast.error
                : data.type === "warning" ? toast.warning
                : data.type === "success" ? toast.success
                : toast.info;
            fn(data.message, { duration: 5000 });
        });

        (socket as any).on("vault:rejected", (data: { id: string; catalogId: string; catalogName: string; nicheIds: string[]; imageUrl: string; reason: string; score: number }) => {
            setRejectedImages(prev => [{
                _id: data.id,
                catalogId: data.catalogId,
                catalogName: data.catalogName,
                nicheIds: data.nicheIds,
                imageUrl: data.imageUrl,
                reason: data.reason,
                score: data.score,
                prompt: "",
                createdAt: new Date().toISOString(),
            }, ...prev]);
            setIsVaultExpanded(true);
            toast.warning(`Imagen rechazada → vault (${data.reason})`);
        });

        (socket as any).on("vault:updated", (data: { id: string; reviewStatus: string }) => {
            if (data.reviewStatus !== "pending") {
                setRejectedImages(prev => prev.filter(r => r._id !== data.id));
            }
        });

        (socket as any).on("kdp:status", (data: { nicheId: string; status: string; message?: string }) => {
            const s = data.status as "idle" | "queued" | "login" | "uploading-pdf" | "done" | "error";
            setKdpPublishStatus(prev => ({ ...prev, [data.nicheId]: s }));
            if (data.status === "error" && data.message) {
                setKdpPublishError(prev => ({ ...prev, [data.nicheId]: data.message! }));
                toast.error(`KDP error: ${data.message.slice(0, 80)}`);
            } else if (data.status === "done") {
                toast.success("✅ KDP borrador guardado en Amazon");
                void fetchNiches();
            }
        });

        return () => {
            socket.disconnect();
            catalogSocketRef.current = null;
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // Track catalog start times and update historical avg on completion
    useEffect(() => {
        iaCatalogs.forEach(c => {
            if ((c.status === "running" || c.status === "pending") && !catalogStartTimeRef.current[c._id]) {
                catalogStartTimeRef.current[c._id] = Date.now();
            }
        });
        iaCatalogs.forEach(c => {
            const startedAt = catalogStartTimeRef.current[c._id];
            if (!startedAt) return;
            if (c.status === "completed" && c.images.length > 0) {
                const secsPerImg = (Date.now() - startedAt) / 1000 / c.images.length;
                avgSecsPerImageRef.current = avgSecsPerImageRef.current * 0.7 + secsPerImg * 0.3;
                delete catalogStartTimeRef.current[c._id];
            } else if (c.status === "cancelled" || c.status === "failed") {
                delete catalogStartTimeRef.current[c._id];
            }
        });
    }, [iaCatalogs]);

    // Build pipeline book draft once all pending catalogs complete
    useEffect(() => {
        if (pipelineBookPendingRef.current.size === 0) return;
        const ready: string[] = [];
        for (const [nicheId, pending] of pipelineBookPendingRef.current.entries()) {
            const allDone = pending.catalogIds.every(cid =>
                iaCatalogs.find(c => c._id === cid)?.status === "completed"
            );
            if (allDone) ready.push(nicheId);
        }
        for (const nicheId of ready) {
            const pending = pipelineBookPendingRef.current.get(nicheId)!;
            pipelineBookPendingRef.current.delete(nicheId);
            const nicheName = pending.nicheName;
            const catImgs = iaCatalogs
                .filter(c => pending.catalogIds.includes(c._id))
                .flatMap(c => c.images.map(img => ({ url: img.url, publicId: img.publicId })));
            const cloudImgs = cloudinaryImages
                .filter(img => img.nicheId === nicheId)
                .map(img => ({ url: img.url, publicId: img.publicId }));
            const allImgs = [...catImgs, ...cloudImgs];
            if (allImgs.length === 0) continue;
            const shuffled = [...allImgs].sort(() => Math.random() - 0.5);
            const ts = Date.now();
            const pages: BookPage[] = [];
            pages.push({ id: `pipe-owner-${ts}`, type: "owner", text: defaultTextStyle() });
            const titleStyle = defaultTextStyle();
            titleStyle.content = nicheName || "Mi Libro de Colorear";
            titleStyle.fontSize = 24; titleStyle.bold = true;
            titleStyle.verticalAlign = "middle"; titleStyle.align = "center";
            pages.push({ id: `pipe-title-${ts}`, type: "text", text: titleStyle });
            pages.push({ id: `pipe-titleback-${ts}`, type: "text", text: defaultTextStyle() });
            shuffled.forEach((img, i) => {
                pages.push({ id: `pipe-img-${i}-${ts}`, type: "image", image: { url: img.url, scale: 1, label: `${nicheName} #${i + 1}` }, text: defaultTextStyle() });
                pages.push({ id: `pipe-blank-${i}-${ts}`, type: "text", text: defaultTextStyle() });
                if ((i + 1) % pending.imagesPerCatalog === 0 && i + 1 < shuffled.length)
                    pages.push({ id: `pipe-ct-${i}-${ts}`, type: "owner", text: defaultTextStyle() });
            });
            const newDraft = { id: `pipeline-${nicheId}-${ts}`, fileName: `${nicheName} — Pipeline Draft`, pages, savedAt: new Date().toISOString(), nicheId };
            // Save to MongoDB and use the returned _id as the draft's id
            fetch(`${API_BASE_URL}/book-drafts`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ fileName: newDraft.fileName, pages, nicheId, savedAt: newDraft.savedAt }),
            }).then(r => r.ok ? r.json() : null).then(data => {
                const savedId = data?.draft?._id ? String(data.draft._id) : newDraft.id;
                setBookDrafts(prev => {
                    const filtered = prev.filter(d => !d.id.startsWith(`pipeline-${nicheId}`) && d.nicheId !== nicheId);
                    return [{ ...newDraft, id: savedId }, ...filtered];
                });
            }).catch(() => {
                setBookDrafts(prev => {
                    const filtered = prev.filter(d => !d.id.startsWith(`pipeline-${nicheId}`) && d.nicheId !== nicheId);
                    return [newDraft, ...filtered];
                });
            });
            void fetch(`${API_BASE_URL}/niches/${nicheId}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ phase: "libro" }) }).catch(() => {});
            setNiches(prev => prev.map(n => n._id === nicheId ? { ...n, phase: "libro" } : n));
            toast.success(`Borrador listo · ${shuffled.length} imágenes · "${nicheName}"`);
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [iaCatalogs]);

    // Live countdown timer for queue estimate
    useEffect(() => {
        const active = iaCatalogs.filter(c => c.status === "running" || c.status === "pending" || c.status === "queued");
        if (active.length === 0) { setQueueEstimateMs(null); return; }
        const interval = setInterval(() => {
            let totalMs = 0;
            const avgMs = avgSecsPerImageRef.current * 1000;
            for (const c of iaCatalogs.filter(cat => cat.status === "running" || cat.status === "pending" || cat.status === "queued")) {
                const remaining = Math.max(0, c.totalImages - c.images.length - (c.skippedImages ?? 0));
                const startedAt = catalogStartTimeRef.current[c._id];
                if ((c.status === "running" || c.status === "pending") && startedAt && c.images.length > 0) {
                    const elapsed = Date.now() - startedAt;
                    const msPerImg = elapsed / c.images.length;
                    totalMs += remaining * msPerImg;
                } else {
                    totalMs += remaining * avgMs;
                }
            }
            setQueueEstimateMs(Math.max(0, totalMs));
        }, 1000);
        return () => clearInterval(interval);
    }, [iaCatalogs]);

    // Tick every second while any catalog is running (drives image elapsed-time color coding)
    useEffect(() => {
        const hasRunning = iaCatalogs.some(c => c.status === "running" && c.imageStartedAt);
        if (!hasRunning) return;
        const interval = setInterval(() => setImageElapsedTick(t => t + 1), 1000);
        return () => clearInterval(interval);
    }, [iaCatalogs]);

    // Sincronizar estado de carga cuando cambia la URL
    useEffect(() => {
        if (generatedImage) {
            setIsImageLoading(true);
        }
    }, [generatedImage]);

    // Pre-fill edit + publish state when opening Acciones tab in niche detail modal
    useEffect(() => {
        if (nicheDetailTab === "actions" && nicheDetailId) {
            const niche = niches.find(n => n._id === nicheDetailId);
            if (niche) {
                setNicheEditTarget(niche);
                setNicheFormName(niche.name);
                setNicheFormDesc(niche.description);
                setNicheFormTags(niche.tags.join(", "));
                setNicheFormStatus(niche.status);
                setNicheFormComp(niche.competition);
                setNicheFormDemand(niche.demand);
                setNicheFormProductType(niche.productType ?? "coloring-book");
                setNicheFormStyles(niche.styleCategories?.length ? niche.styleCategories : [niche.styleCategory ?? "generic"]);
                setNicheFormNotes(niche.notes);
                setNicheFormEtsyUrl(niche.etsyUrl ?? "");
                setNicheFormPrompt(niche.generatedPrompt ?? "");
                setPublishPanelAsin(niche.asin ?? "");
                setPublishPanelEtsy(niche.etsyUrl ?? "");
                setPublishPanelGumroad(niche.gumroadUrl ?? "");
                setPublishPanelDate(niche.publishedAt ? niche.publishedAt.slice(0, 10) : "");
            }
        }
    }, [nicheDetailTab, nicheDetailId]); // eslint-disable-line react-hooks/exhaustive-deps

    const handleGenerateImage = async (retryCount = 0) => {
        if (!imagePrompt.trim()) return;

        const model = AI_MODELS.find(m => m.id === selectedModel);
        const dimensions = AI_DIMENSIONS.find(d => d.id === selectedDim);

        setIsGenerating(true);
        setGeneratedImage(null);

        try {
            const response = await fetch(`${API_BASE_URL}/ai/generate-image`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    prompt: imagePrompt,
                    modelId: model?.modelId,
                    provider: model?.provider,
                    width: dimensions?.width,
                    height: dimensions?.height,
                    initImage: initImageDataUrl
                        ? { dataUrl: initImageDataUrl, strength: initImageStrength }
                        : undefined,
                    advancedParams: {
                        negativePrompt: negativePrompt.trim() || undefined,
                        steps: (model?.provider === "Hugging Face" || model?.provider === "Leonardo") ? inferenceSteps : undefined,
                        guidanceScale: (model?.provider === "Hugging Face" || model?.provider === "Leonardo") ? guidanceScale : undefined,
                        seed: fixedSeed ? Number(fixedSeed) : undefined,
                        style: model?.provider === "Ideogram" ? ideogramStyle : undefined,
                    },
                })
            });

            if (response.ok) {
                const blob = await response.blob();
                const url = URL.createObjectURL(blob);
                setGeneratedImage(url);
                setIsGenerating(false);
                toast.success("Arte generado con éxito");
                return;
            } else if (response.status === 429 && retryCount < 2) {
                const retryAfter = Number(response.headers.get("Retry-After") || "10");
                const waitMs = Number.isFinite(retryAfter) ? Math.max(3, retryAfter) * 1000 : 10000;
                toast.info(`Límite alcanzado. Reintentando en ${Math.round(waitMs / 1000)}s (${retryCount + 1}/2)`);
                setTimeout(() => handleGenerateImage(retryCount + 1), waitMs);
                return;
            } else if (response.status === 503 && retryCount < 2) {
                toast.info(`El modelo se está cargando... Reintentando (${retryCount + 1}/2)`);
                setTimeout(() => handleGenerateImage(retryCount + 1), 5000);
                return;
            }

            setIsGenerating(false);
            setIsImageLoading(false);
            toast.error("Error generando imagen. Prueba otro modelo o inténtalo de nuevo.");

        } catch (error) {
            console.error("Generation error:", error);
            setIsGenerating(false);
            setIsImageLoading(false);
            toast.error("Error en el motor de generación");
        }
    };

    const handleKeepImage = async () => {
        if (generatedImage) {
            const modelName = AI_MODELS.find(m => m.id === selectedModel)?.name || "Unknown";
            const dimName = AI_DIMENSIONS.find(d => d.id === selectedDim)?.ratio || "1:1";

            let urlToStore = generatedImage;
            try {
                urlToStore = await ensureObjectUrl(generatedImage);
            } catch {
                // keep original URL if it cannot be fetched (may impact PDF generation)
            }

            setVaultImages([{
                url: urlToStore,
                model: modelName,
                dim: dimName,
                seed: fixedSeed ? Number(fixedSeed) : undefined,
            }, ...vaultImages]);
            setGeneratedImage(null);
        }
    };

    const handleDeleteVaultImage = (index: number) => {
        setConfirmDeleteVaultIndex(index);
    };

    const handleAddProduct = () => {
        if (!newTitle.trim()) {
            toast.error("El título es obligatorio");
            return;
        }

        const typeInfo = PRODUCT_TYPES.find(t => t.id === selectedType);

        const mockPlatforms = PLATFORMS.slice(0, Math.floor(Math.random() * 3) + 1).map(name => ({
            name,
            earnings: Math.floor(Math.random() * 100) + 20
        }));
        const totalEarnings = mockPlatforms.reduce((acc, p) => acc + p.earnings, 0);

        const newProduct: DigitalProduct = {
            id: `prod_${Date.now()}`,
            type: typeInfo ? typeInfo.name : "Digital Asset",
            title: newTitle.trim(),
            description: newDesc.trim() || "Generated by KDP Factory AI Engine",
            status: "borrador",
            platforms: mockPlatforms,
            totalEarnings,
            createdAt: new Date().toISOString()
        };

        setProducts([newProduct, ...products]);
        setNewTitle("");
        setNewDesc("");
        toast.success("Producto creado. ¡Revísalo en Insights!");
        changeTab("insights");
    };

