    // ── Upscale image via HuggingFace SR ─────────────────────────────────────
    const upscaleImage = async (url: string, publicId: string) => {
        setUpscalingPublicId(publicId);
        try {
            const imgRes = await fetch(url);
            const blob = await imgRes.blob();
            const dataUrl = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => resolve(reader.result as string);
                reader.onerror = reject;
                reader.readAsDataURL(blob);
            });
            const res = await fetch(`${API_BASE_URL}/ai/upscale`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ dataUrl }),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.error ?? "Error upscaling");
            const a = document.createElement("a");
            a.href = data.dataUrl;
            a.download = `upscaled-${publicId.replace(/\//g, "-")}.png`;
            a.click();
            toast.success("Imagen 4× upscalada y descargada");
        } catch (e: any) {
            toast.error(e.message ?? "Error upscaling");
        } finally {
            setUpscalingPublicId(null);
        }
    };

    // ── Exportar catálogo como dataset HuggingFace (metadata.jsonl) ──────────
    const exportCatalogDataset = (catalog: typeof iaCatalogs[number]) => {
        if (!catalog.images.length) { toast.error("Este catálogo no tiene imágenes"); return; }
        const lines = catalog.images.map(img =>
            JSON.stringify({ file_name: img.publicId.split("/").pop() + "." + (img.url.split(".").pop()?.split("?")[0] ?? "jpg"), url: img.url, prompt: catalog.prompt, catalog: catalog.name, productType: catalog.productType ?? "coloring-book" })
        );
        const blob = new Blob([lines.join("\n")], { type: "application/jsonl" });
        const a = document.createElement("a");
        a.href = URL.createObjectURL(blob);
        a.download = `${catalog.name.replace(/[^a-z0-9]+/gi, "-").toLowerCase()}-dataset.jsonl`;
        a.click();
        URL.revokeObjectURL(a.href);
        toast.success(`Dataset exportado · ${catalog.images.length} entradas`);
    };

    // ── Pipeline automático: genera catálogos + KDP listing ──────────────────
    const runNichePipeline = async (niche: NicheFE, cfg?: { catalogs: number; imagesPerCatalog: number }) => {
        if (pipelineRunningRef.current === niche._id) return; // prevent double-press

        pipelineRunningRef.current = niche._id;
        setPipelineRunningId(niche._id);

        try {
            const IMAGES_PER_CATALOG = cfg?.imagesPerCatalog ?? pipelineConfig.imagesPerCatalog;
            const MAX_CATALOGS = cfg?.catalogs ?? pipelineConfig.catalogs;

            const res = await fetch(`${API_BASE_URL}/niches/${niche._id}/pipeline/run`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ catalogsPerNiche: MAX_CATALOGS, imagesPerCatalog: IMAGES_PER_CATALOG }),
            });

            if (!res.ok) {
                const err = await res.json().catch(() => ({})) as any;
                throw new Error(err.error ?? "Error lanzando pipeline en servidor");
            }

            toast.success(`Pipeline de "${niche.nickname?.trim() || niche.name}" iniciado en servidor`);
            changeTab("niches");
        } catch (e: any) {
            toast.error(e.message ?? "Error en el pipeline");
            pipelineRunningRef.current = null;
            setPipelineRunningId(null);
        }
        // pipelineRunningId is cleared when the autopilot:done socket event fires
    };

    const monthlyEarningsData = useMemo(() => {
        const map = new Map<string, number>();
        products.forEach(p => {
            p.platforms.forEach(pl => {
                const raw = pl.date?.trim();
                let key = "";
                if (raw && raw.length >= 7) {
                    key = raw.slice(0, 7);
                } else {
                    key = p.createdAt ? p.createdAt.slice(0, 7) : "";
                }
                if (key) map.set(key, (map.get(key) ?? 0) + (pl.earnings || 0));
            });
        });
        return [...map.entries()].sort((a, b) => a[0].localeCompare(b[0])).slice(-12).map(([month, earnings]) => ({ month, earnings }));
    }, [products]);

